"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[669],{3787:e=>{e.exports=JSON.parse('{"functions":[{"name":"NewEcosystem","desc":"Creates a new `Ecosystem` object\\n\\n## Example\\n```lua\\nlocal Ecosystem = require(\\"Path to ecosystem module\\")\\nlocal EcosystemObject1 = Ecosystem.NewEcosystem(\\"TestEcosystem\\")\\n\\nprint(EcosystemObject1.ClassName) -- Ecosystem\\n```","params":[{"name":"Identifyer","desc":"the ID assigned to the current Ecosystem object","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Ecosystem"}],"function_type":"static","tags":["Constructor"],"source":{"line":1263,"path":"src/init.luau"}},{"name":"NewSpecies","desc":"Creates a new `Species` object from the passed `Ecosystem` Identifyer\\n\\n:::caution Must freeze\\nBefore creating a `Species` object you must first call `Ecosystem:Freeze()` you can check if a Ecosystem is frozen with `Ecosystem.Frozen`\\n:::\\n\\n## Example\\n```lua\\nlocal Ecosystem = require(\\"Path to ecosystem module\\")\\nlocal EcosystemObject1 = Ecosystem.NewEcosystem(\\"TestEcosystem\\")\\n\\nprint(EcosystemObject1.ClassName) -- Ecosystem\\n\\n-- Turns the Ecosystem object into a read-only template\\nEcosystemObject1:Freeze()\\n\\nlocal TestSpecies = Ecosystem.NewSpecies(\\"TestEcosystem\\")\\n\\nprint(TestSpecies.ClassName) -- Species\\n```","params":[{"name":"Identifyer","desc":"the ID assigned to the current Ecosystem object","lua_type":"string"},{"name":"ObjectToBind","desc":"The optional instance to be binded to the species object","lua_type":"Instance?"}],"returns":[{"desc":"","lua_type":"Species"}],"function_type":"static","tags":["Constructor"],"source":{"line":1328,"path":"src/init.luau"}},{"name":"GetSpeciesFromBindedInstance","desc":"Gets the species object binded to a instance\\n\\n:::tip Time-Complexity\\nProviding a controller object will change the time complexity to `O(n)` instead of the default without `O(n^2)`. **NOTE** if a controller is provided it will only search the controller that is passed.\\n:::\\n\\n## Example\\n```lua\\nlocal Ecosystem = require(\\"Path to ecosystem module\\")\\nlocal EcosystemObject1 = Ecosystem.NewEcosystem(\\"TestEcosystem\\")\\nlocal TestNPC = workspace.NPC\\n\\n-- Turns the Ecosystem object into a read-only template\\nEcosystemObject1:Freeze()\\n\\nlocal TestSpecies = Ecosystem.NewSpecies(\\"TestEcosystem\\", TestNPC)\\n\\nprint(TestSpecies.ObjectBinded == TestNPC) -- true\\n\\n-- The same Species object\\nlocal TestSpecies2 = Ecosystem:GetSpeciesFromBindedInstance(TestNPC, EcosystemObject1)\\n\\nprint(TestSpecies2.ObjectBinded == TestNPC) -- true\\n\\n```","params":[{"name":"I","desc":"A instance that potentially has a species object binded to it","lua_type":"Instance"},{"name":"Controller","desc":"Searches the Controller object instead of global","lua_type":"Ecosystem?"}],"returns":[{"desc":"","lua_type":"Species?"}],"function_type":"method","source":{"line":1414,"path":"src/init.luau"}},{"name":"GetEcosystemFromSpecie","desc":"Gets the Ecosystem object binded to the passed Species\\n\\n## Example\\n```lua\\nlocal Ecosystem = require(\\"Path to ecosystem module\\")\\nlocal EcosystemObject1 = Ecosystem.NewEcosystem(\\"TestEcosystem\\")\\n\\n-- Turns the Ecosystem object into a read-only template\\nEcosystemObject1:Freeze()\\n\\nlocal TestSpecies = Ecosystem.NewSpecies(\\"TestEcosystem\\")\\n\\nprint(EcosystemObject1.EcosystemID) -- TestEcosystem\\n\\n-- The same Ecosystem object\\nlocal EcosystemObject2 = Ecosystem:GetEcosystemFromSpecie(TestSpecies)\\n\\nprint(EcosystemObject1.EcosystemID) -- TestEcosystem\\n\\n```","params":[{"name":"S","desc":"The species you want to get the controller for","lua_type":"Species"}],"returns":[{"desc":"","lua_type":"Ecosystem?"}],"function_type":"method","source":{"line":1469,"path":"src/init.luau"}}],"properties":[],"types":[],"name":"EcosystemGlobalServices","desc":"The constructor class of [Ecosystem](../Ecosystem/) & [Species](../Species/) + other global features.\\n\\n:::info Module return\\n`EcosystemGlobalServices` is the dictionary that is returned after calling `require(\'Ecosystem\')`\\n:::","source":{"line":1241,"path":"src/init.luau"}}')}}]);